/**
 * embeddings.ts — Gemini embedding client for brain.db
 *
 * Uses gemini-embedding-001 at 768 dimensions.
 * Provides single text and batch embedding with retry logic.
 *
 * Requires GOOGLE_API_KEY in .env (same as gemini.ts).
 */

import { GoogleGenAI } from "@google/genai";
import { trackUsage } from "./ai-usage.js";

// ── Config ──────────────────────────────────────────────────────────────

const EMBED_MODEL = "gemini-embedding-001";
const EMBED_DIMS = 768;
const MAX_BATCH_SIZE = 100;
const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 1000;

// ── Client ──────────────────────────────────────────────────────────────

let _client: GoogleGenAI | null = null;

function getClient(): GoogleGenAI {
  if (_client) return _client;

  const apiKey = process.env.GOOGLE_API_KEY;
  if (!apiKey) {
    throw new Error(
      "GOOGLE_API_KEY not set. Required for embeddings.\n" +
      "Get your key at: https://aistudio.google.com/apikey"
    );
  }

  _client = new GoogleGenAI({ apiKey });
  return _client;
}

// ── Helpers ─────────────────────────────────────────────────────────────

async function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/** Convert number[] to Buffer (float32) for sqlite-vec storage */
export function vectorToBuffer(embedding: number[]): Buffer {
  return Buffer.from(new Float32Array(embedding).buffer);
}

/** Convert Buffer (float32) back to number[] */
export function bufferToVector(buf: Buffer): number[] {
  return Array.from(new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4));
}

/** Approximate token count (rough: 1 token ≈ 4 chars) */
export function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

// ── Single Embed ────────────────────────────────────────────────────────

/**
 * Embed a single text string.
 *
 * @param text - Text to embed
 * @param caller - Who's calling (for usage tracking)
 * @returns 768-dim float array
 */
export async function embedText(text: string, caller = "unknown"): Promise<number[]> {
  const client = getClient();
  let lastError: Error | null = null;

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const result = await client.models.embedContent({
        model: EMBED_MODEL,
        contents: text,
        config: { outputDimensionality: EMBED_DIMS },
      });

      const values = result.embeddings?.[0]?.values;
      if (!values || values.length === 0) {
        throw new Error("Empty embedding response");
      }

      // Track usage
      const tokens = estimateTokens(text);
      trackUsage({
        model: EMBED_MODEL,
        inputTokens: tokens,
        outputTokens: 0,
        caller,
        cost: tokens * 0.00000015, // $0.15/1M tokens
      });

      return values;
    } catch (err: any) {
      lastError = err;
      if (attempt < MAX_RETRIES - 1) {
        await sleep(RETRY_DELAY_MS * (attempt + 1));
      }
    }
  }

  throw new Error(`Embedding failed after ${MAX_RETRIES} attempts: ${lastError?.message}`);
}

// ── Batch Embed ─────────────────────────────────────────────────────────

export interface BatchEmbedResult {
  embeddings: (number[] | null)[];
  succeeded: number;
  failed: number;
  totalTokens: number;
}

/**
 * Embed multiple texts in batches.
 *
 * @param texts - Array of texts to embed
 * @param caller - Who's calling (for usage tracking)
 * @returns Array of embeddings (null for failed items)
 */
export async function embedBatch(texts: string[], caller = "unknown"): Promise<BatchEmbedResult> {
  const client = getClient();
  const results: (number[] | null)[] = new Array(texts.length).fill(null);
  let succeeded = 0;
  let failed = 0;
  let totalTokens = 0;

  // Process in chunks of MAX_BATCH_SIZE
  for (let i = 0; i < texts.length; i += MAX_BATCH_SIZE) {
    const batch = texts.slice(i, i + MAX_BATCH_SIZE);
    const batchTokens = batch.reduce((sum, t) => sum + estimateTokens(t), 0);

    let lastError: Error | null = null;
    let batchSuccess = false;

    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        // Embed each item individually within the batch
        // (Gemini embedContent takes a single content string per call)
        const promises = batch.map((text) =>
          client.models.embedContent({
            model: EMBED_MODEL,
            contents: text,
            config: { outputDimensionality: EMBED_DIMS },
          })
        );

        const responses = await Promise.all(promises);

        for (let j = 0; j < responses.length; j++) {
          const values = responses[j].embeddings?.[0]?.values;
          if (values && values.length > 0) {
            results[i + j] = values;
            succeeded++;
          } else {
            failed++;
          }
        }

        totalTokens += batchTokens;
        batchSuccess = true;
        break;
      } catch (err: any) {
        lastError = err;
        if (attempt < MAX_RETRIES - 1) {
          await sleep(RETRY_DELAY_MS * (attempt + 1));
        }
      }
    }

    if (!batchSuccess) {
      // Mark entire batch as failed
      for (let j = 0; j < batch.length; j++) {
        results[i + j] = null;
        failed++;
      }
      console.error(`Batch ${Math.floor(i / MAX_BATCH_SIZE) + 1} failed: ${lastError?.message}`);
    }
  }

  // Track total usage
  if (totalTokens > 0) {
    trackUsage({
      model: EMBED_MODEL,
      inputTokens: totalTokens,
      outputTokens: 0,
      caller,
      cost: totalTokens * 0.00000015,
    });
  }

  return { embeddings: results, succeeded, failed, totalTokens };
}

// ── Metadata ────────────────────────────────────────────────────────────

export const EMBEDDING_CONFIG = {
  model: EMBED_MODEL,
  dimensions: EMBED_DIMS,
  maxBatchSize: MAX_BATCH_SIZE,
} as const;

