/**
 * embeddings.ts — Local ONNX embedding client for brain.db
 *
 * Uses @huggingface/transformers with Xenova/all-MiniLM-L6-v2 at 384 dimensions.
 * Inference is local — no API key required, no network calls after initial model download.
 * Model files (~22MB) are auto-downloaded on first use to ~/.cache/huggingface/.
 *
 * Backend path: @huggingface/transformers ONNX pipeline (default WASM backend on Bun/Windows).
 */

import { pipeline, type FeatureExtractionPipeline } from "@huggingface/transformers";
import { trackUsage } from "./ai-usage.js";

// ── Config ──────────────────────────────────────────────────────────────

const EMBED_MODEL = "all-MiniLM-L6-v2";
const EMBED_DIMS = 384;
const MAX_BATCH_SIZE = 100;

// ── Pipeline ────────────────────────────────────────────────────────────

let _pipeline: FeatureExtractionPipeline | null = null;

async function getPipeline(): Promise<FeatureExtractionPipeline> {
  if (_pipeline) return _pipeline;
  _pipeline = await pipeline("feature-extraction", "Xenova/all-MiniLM-L6-v2");
  return _pipeline;
}

// ── Helpers ─────────────────────────────────────────────────────────────

/** Convert number[] to Buffer (float32) for sqlite-vec storage */
export function vectorToBuffer(embedding: number[]): Buffer {
  return Buffer.from(new Float32Array(embedding).buffer);
}

/** Convert Buffer (float32) back to number[] */
export function bufferToVector(buf: Buffer): number[] {
  return Array.from(new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4));
}

/** Approximate token count (rough: 1 token ≈ 4 chars) */
export function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

// ── Single Embed ────────────────────────────────────────────────────────

/**
 * Embed a single text string using local ONNX model.
 * Lazy-loads the pipeline on first call, caches for reuse.
 *
 * @param text - Text to embed
 * @param caller - Who's calling (for usage tracking)
 * @returns 384-dim float array
 */
export async function embedText(text: string, caller = "unknown"): Promise<number[]> {
  const pipe = await getPipeline();
  const output = await pipe(text, { pooling: "mean", normalize: true });
  const values: number[] = Array.from(output.data as Float32Array);

  const tokens = estimateTokens(text);
  trackUsage({
    provider: "local",
    model: EMBED_MODEL,
    inputTokens: tokens,
    outputTokens: 0,
    caller,
    costUsd: 0,
  });

  return values;
}

// ── Batch Embed ─────────────────────────────────────────────────────────

export interface BatchEmbedResult {
  embeddings: (number[] | null)[];
  succeeded: number;
  failed: number;
  totalTokens: number;
}

/**
 * Embed multiple texts in batches using local ONNX model.
 *
 * @param texts - Array of texts to embed
 * @param caller - Who's calling (for usage tracking)
 * @returns Array of embeddings (null for failed items)
 */
export async function embedBatch(texts: string[], caller = "unknown"): Promise<BatchEmbedResult> {
  const pipe = await getPipeline();
  const results: (number[] | null)[] = new Array(texts.length).fill(null);
  let succeeded = 0;
  let failed = 0;
  let totalTokens = 0;

  for (let i = 0; i < texts.length; i += MAX_BATCH_SIZE) {
    const batch = texts.slice(i, i + MAX_BATCH_SIZE);
    const batchTokens = batch.reduce((sum, t) => sum + estimateTokens(t), 0);

    for (let j = 0; j < batch.length; j++) {
      try {
        const output = await pipe(batch[j], { pooling: "mean", normalize: true });
        results[i + j] = Array.from(output.data as Float32Array);
        succeeded++;
      } catch (err: any) {
        results[i + j] = null;
        failed++;
        console.error(`[embedBatch] Item ${i + j} failed: ${err.message}`);
      }
    }

    totalTokens += batchTokens;
  }

  if (totalTokens > 0) {
    trackUsage({
      provider: "local",
      model: EMBED_MODEL,
      inputTokens: totalTokens,
      outputTokens: 0,
      caller,
      costUsd: 0,
    });
  }

  return { embeddings: results, succeeded, failed, totalTokens };
}

// ── Metadata ────────────────────────────────────────────────────────────

export const EMBEDDING_CONFIG = {
  model: EMBED_MODEL,
  dimensions: EMBED_DIMS,
  maxBatchSize: MAX_BATCH_SIZE,
} as const;

