/**
 * brain/queries.ts — Query functions for brain.db
 *
 * All search functions use FTS5 with BM25 ranking.
 * Decision functions handle logging, recall, and outcome updates.
 */

import { eq, and, desc, sql } from "drizzle-orm";
import { getDb, getRawDb } from "../sqlite.js";
import { memories, references, decisions, entities, entityRelations, syncMeta } from "./schema.js";
import { vectorToBuffer, embedText, EMBEDDING_CONFIG } from "../embeddings.js";
import { rerankResults } from "./reranker.js";
import { knowledgeStaleness, decayedConfidence } from "./degradation.js";

/**
 * Sanitize a user query for FTS5.
 * - Wraps each token in quotes to avoid operator parsing (e.g., lo-fi → "lo-fi")
 * - Joins with spaces (implicit AND in FTS5)
 */
function sanitizeFtsQuery(query: string): string {
  return query
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((token) => `"${token.replace(/"/g, "")}"`)
    .join(" ");
}

// ─── Types ───────────────────────────────────────────────────

export interface SearchResult {
  id: number;
  title: string;
  snippet: string;
  tags: string | null;
  sourcePath: string;
  rank: number;
}

export interface MemoryResult extends SearchResult {
  agent: string;
  tier: string;
  memoryType: string | null;
}

export interface ReferenceResult extends SearchResult {
  collection: string;
  frontmatter: string | null;
}

export interface DecisionResult {
  id: number;
  agent: string;
  decision: string;
  context: string;
  alternatives: string | null;
  outcome: string | null;
  confidence: number | null;
  decayedConfidence: number | null;
  tags: string | null;
  createdAt: string;
}

// ─── Confidence decay ───────────────────────────────────────

/**
 * Compute decayed confidence based on age.
 * Full confidence for ~30 days, linear decay to floor of 0.3 at 90 days.
 * Formula: confidence * max(0.3, 1 - (daysSince / 90))
 */
export function computeDecayedConfidence(confidence: number | null, createdAt: string): number | null {
  if (confidence == null) return null;
  const daysSince = (Date.now() - new Date(createdAt).getTime()) / (1000 * 60 * 60 * 24);
  const decayFactor = Math.max(0.3, 1 - daysSince / 90);
  return Math.round(confidence * decayFactor * 100) / 100;
}

export interface SearchOpts {
  agent?: string;
  tier?: string;
  collection?: string;
  memoryType?: string;
  limit?: number;
}

// ─── Memory search ───────────────────────────────────────────

/**
 * Full-text search across memory files.
 * Returns BM25-ranked results with snippets.
 */
export function searchMemories(query: string, opts?: SearchOpts): MemoryResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 20;
  const safeQuery = sanitizeFtsQuery(query);

  let sql = `
    SELECT m.id, m.agent, m.tier, m.title, m.tags, m.memory_type, m.source_path,
           snippet(memories_fts, 1, '<b>', '</b>', '...', 32) as snippet,
           rank
    FROM memories_fts
    JOIN memories m ON m.id = memories_fts.rowid
    WHERE memories_fts MATCH ?
  `;
  const params: any[] = [safeQuery];

  if (opts?.agent) {
    sql += " AND m.agent = ?";
    params.push(opts.agent);
  }
  if (opts?.tier) {
    sql += " AND m.tier = ?";
    params.push(opts.tier);
  }
  if (opts?.memoryType) {
    sql += " AND m.memory_type = ?";
    params.push(opts.memoryType);
  }

  sql += " ORDER BY rank LIMIT ?";
  params.push(limit);

  const rows = raw.prepare(sql).all(...params) as any[];
  return rows.map((r) => ({
    id: r.id,
    agent: r.agent,
    tier: r.tier,
    title: r.title,
    snippet: r.snippet,
    tags: r.tags,
    memoryType: r.memory_type,
    sourcePath: r.source_path,
    rank: r.rank,
  }));
}

// ─── Reference search ────────────────────────────────────────

/**
 * Full-text search across reference files.
 * Returns BM25-ranked results with snippets.
 */
export function searchReferences(query: string, opts?: SearchOpts): ReferenceResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 20;
  const safeQuery = sanitizeFtsQuery(query);

  let sql = `
    SELECT r.id, r.collection, r.title, r.tags, r.frontmatter, r.source_path,
           snippet(references_fts, 1, '<b>', '</b>', '...', 32) as snippet,
           rank
    FROM references_fts
    JOIN 'references' r ON r.id = references_fts.rowid
    WHERE references_fts MATCH ?
  `;
  const params: any[] = [safeQuery];

  if (opts?.collection) {
    sql += " AND r.collection = ?";
    params.push(opts.collection);
  }

  sql += " ORDER BY rank LIMIT ?";
  params.push(limit);

  const rows = raw.prepare(sql).all(...params) as any[];
  return rows.map((r) => ({
    id: r.id,
    collection: r.collection,
    title: r.title,
    snippet: r.snippet,
    tags: r.tags,
    frontmatter: r.frontmatter,
    sourcePath: r.source_path,
    rank: r.rank,
  }));
}

// ─── Decision logging ────────────────────────────────────────

export interface DecisionInput {
  agent: string;
  decision: string;
  context: string;
  alternatives?: string;
  outcome?: string;
  confidence?: number;
  tags?: string;
  project?: string;
  projectPath?: string;
  rawRef?: number;
}

/** Log a new decision. Returns the inserted row ID. Embeds async (fire-and-forget). */
export function logDecision(input: DecisionInput): number {
  const db = getDb();
  const ts = new Date().toISOString();

  const [row] = db.insert(decisions).values({
    agent: input.agent,
    decision: input.decision,
    context: input.context,
    alternatives: input.alternatives ?? null,
    outcome: input.outcome ?? null,
    confidence: input.confidence ?? 0.5,
    tags: input.tags ?? null,
    project: input.project ?? "unknown",
    projectPath: input.projectPath ?? null,
    rawRef: input.rawRef ?? null,
    createdAt: ts,
    updatedAt: ts,
  }).returning({ id: decisions.id }).all();

  const id = row.id;

  // Fire-and-forget embed — don't block the caller
  const embedTextParts = [input.decision, `Context: ${input.context}`];
  if (input.alternatives) embedTextParts.push(`Alternatives: ${input.alternatives}`);
  embedDecisionAsync(id, embedTextParts.join(". "));

  return id;
}

/** Embed a decision asynchronously — failures are silent (caught up on next sync) */
function embedDecisionAsync(id: number, text: string): void {
  embedText(text, "logDecision").then((embedding) => {
    setDecisionEmbedding(id, embedding, EMBEDDING_CONFIG.model);
  }).catch(() => {
    // Silently fail — batch catch-up on next sync will handle it
  });
}

/** Update outcome and confidence for an existing decision. Re-embeds async. */
export function updateOutcome(id: number, outcome: string, confidence: number): void {
  const db = getDb();
  const ts = new Date().toISOString();

  db.update(decisions)
    .set({ outcome, confidence, updatedAt: ts })
    .where(eq(decisions.id, id))
    .run();

  // Re-embed with outcome context
  const row = db.select({
    decision: decisions.decision,
    context: decisions.context,
    alternatives: decisions.alternatives,
  }).from(decisions).where(eq(decisions.id, id)).get();
  if (row) {
    const parts = [row.decision, `Context: ${row.context}`];
    if (row.alternatives) parts.push(`Alternatives: ${row.alternatives}`);
    parts.push(`Outcome: ${outcome}`);
    embedDecisionAsync(id, parts.join(". "));
  }
}

// ─── Decision recall ─────────────────────────────────────────

/** Full-text search across past decisions. */
export function searchDecisions(query: string, opts?: SearchOpts): DecisionResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 20;
  const safeQuery = sanitizeFtsQuery(query);

  let sql = `
    SELECT d.id, d.agent, d.decision, d.context, d.alternatives,
           d.outcome, d.confidence, d.tags, d.created_at
    FROM decisions_fts
    JOIN decisions d ON d.id = decisions_fts.rowid
    WHERE decisions_fts MATCH ?
  `;
  const params: any[] = [safeQuery];

  if (opts?.agent) {
    sql += " AND d.agent = ?";
    params.push(opts.agent);
  }

  sql += " ORDER BY rank LIMIT ?";
  params.push(limit);

  const rows = raw.prepare(sql).all(...params) as any[];
  return rows.map((r) => ({
    id: r.id,
    agent: r.agent,
    decision: r.decision,
    context: r.context,
    alternatives: r.alternatives,
    outcome: r.outcome,
    confidence: r.confidence,
    decayedConfidence: computeDecayedConfidence(r.confidence, r.created_at),
    tags: r.tags,
    createdAt: r.created_at,
  }));
}

/** Get recent decisions for an agent (no FTS, just chronological). */
export function getDecisionHistory(agent: string, opts?: { limit?: number }): DecisionResult[] {
  const db = getDb();
  const limit = opts?.limit ?? 20;

  const rows = db
    .select()
    .from(decisions)
    .where(eq(decisions.agent, agent))
    .orderBy(desc(decisions.createdAt))
    .limit(limit)
    .all();

  return rows.map((r) => ({
    id: r.id,
    agent: r.agent,
    decision: r.decision,
    context: r.context,
    alternatives: r.alternatives,
    outcome: r.outcome,
    confidence: r.confidence,
    decayedConfidence: computeDecayedConfidence(r.confidence, r.createdAt),
    tags: r.tags,
    createdAt: r.createdAt,
  }));
}

// ─── Vector search ──────────────────────────────────────────

/** Cosine similarity between two vectors */
function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) return 0;
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

/** Reinforce a knowledge memory — bumps last_reinforced_at to now */
export function reinforceMemory(sourcePath: string): void {
  const db = getDb();
  db.update(memories)
    .set({ lastReinforcedAt: new Date().toISOString() })
    .where(eq(memories.sourcePath, sourcePath))
    .run();
}

/** Store an embedding for a memory row (Drizzle update + sqlite-vec) */
export function setMemoryEmbedding(sourcePath: string, embedding: number[], model?: string): void {
  const db = getDb();
  const raw = getRawDb();
  const ts = new Date().toISOString();
  const buf = vectorToBuffer(embedding);

  db.update(memories)
    .set({ embedding: JSON.stringify(embedding), embedModel: model ?? null, embeddedAt: ts })
    .where(eq(memories.sourcePath, sourcePath))
    .run();

  // Get the memory id for vec table
  const row = db.select({ id: memories.id }).from(memories).where(eq(memories.sourcePath, sourcePath)).get();
  if (row) {
    try {
      raw.prepare("INSERT INTO vec_memories(memory_id, embedding) VALUES (?, ?)").run(row.id, buf);
    } catch {
      raw.prepare("UPDATE vec_memories SET embedding = ? WHERE memory_id = ?").run(buf, row.id);
    }
  }
}

/** Store an embedding for a decision row (Drizzle update + sqlite-vec) */
export function setDecisionEmbedding(id: number, embedding: number[], model?: string): void {
  const db = getDb();
  const raw = getRawDb();
  const ts = new Date().toISOString();
  const buf = vectorToBuffer(embedding);

  db.update(decisions)
    .set({ embedding: JSON.stringify(embedding), embedModel: model ?? null, embeddedAt: ts })
    .where(eq(decisions.id, id))
    .run();

  // vec table — raw SQL (sqlite-vec virtual table)
  try {
    raw.prepare("INSERT INTO vec_decisions(decision_id, embedding) VALUES (?, ?)").run(id, buf);
  } catch {
    raw.prepare("UPDATE vec_decisions SET embedding = ? WHERE decision_id = ?").run(buf, id);
  }
}

export interface VectorSearchResult {
  id: number;
  title: string;
  sourcePath: string;
  agent: string;
  similarity: number;
}

/**
 * Vector search across memories using sqlite-vec KNN.
 * Falls back to JS cosine similarity if vec table is empty.
 */
export function vectorSearchMemories(
  queryEmbedding: number[],
  opts?: { agent?: string; tier?: string; memoryType?: string; limit?: number },
): VectorSearchResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 10;
  const queryBuf = vectorToBuffer(queryEmbedding);

  // Try sqlite-vec KNN first
  try {
    const vecCount = (raw.prepare("SELECT COUNT(*) as c FROM vec_memories").get() as any).c;
    if (vecCount > 0) {
      const rows = raw.prepare(`
        SELECT vm.memory_id, vm.distance, m.agent, m.tier, m.title, m.source_path
        FROM vec_memories vm
        JOIN memories m ON m.id = vm.memory_id
        WHERE vm.embedding MATCH ? AND k = ?
        ORDER BY vm.distance
      `).all(queryBuf, limit) as any[];

      const maxDist = Math.max(...rows.map((r: any) => r.distance), 0.001);
      return rows.map((r: any) => ({
        id: r.memory_id,
        title: r.title,
        sourcePath: r.source_path,
        agent: r.agent,
        similarity: 1 - (r.distance / maxDist),
      }));
    }
  } catch {}

  // Fallback to JS cosine
  let sql = "SELECT id, agent, tier, title, source_path, embedding FROM memories WHERE embedding IS NOT NULL";
  const params: any[] = [];
  if (opts?.agent) { sql += " AND agent = ?"; params.push(opts.agent); }
  if (opts?.tier) { sql += " AND tier = ?"; params.push(opts.tier); }
  if (opts?.memoryType) { sql += " AND memory_type = ?"; params.push(opts.memoryType); }

  const rows = raw.prepare(sql).all(...params) as any[];
  return rows
    .map((r) => ({
      id: r.id as number, title: r.title as string,
      sourcePath: r.source_path as string, agent: r.agent as string,
      similarity: cosineSimilarity(queryEmbedding, JSON.parse(r.embedding)),
    }))
    .sort((a, b) => b.similarity - a.similarity)
    .slice(0, limit);
}

export interface HybridSearchResult {
  id: number;
  title: string;
  sourcePath: string;
  agent: string;
  ftsRank: number | null;
  similarity: number | null;
  combinedScore: number;
}

/**
 * Hybrid search: FTS5 keyword + vector similarity, merged by weighted score.
 * ftsWeight and vectorWeight control the blend (default 0.4 FTS + 0.6 vector).
 */
export function hybridSearchMemories(
  query: string,
  queryEmbedding: number[],
  opts?: SearchOpts & { ftsWeight?: number; vectorWeight?: number },
): HybridSearchResult[] {
  const limit = opts?.limit ?? 10;
  const ftsWeight = opts?.ftsWeight ?? 0.4;
  const vectorWeight = opts?.vectorWeight ?? 0.6;

  // Get FTS results
  const ftsResults = searchMemories(query, { ...opts, limit: limit * 2 });
  // Get vector results
  const vecResults = vectorSearchMemories(queryEmbedding, { ...opts, limit: limit * 2 });

  // Normalize scores
  const maxFtsRank = Math.min(...ftsResults.map(r => r.rank), -0.001); // FTS rank is negative, lower = better
  const maxSimilarity = Math.max(...vecResults.map(r => r.similarity), 0.001);

  // Merge by sourcePath
  const merged = new Map<string, HybridSearchResult>();

  for (const r of ftsResults) {
    const normalizedFts = r.rank / maxFtsRank; // 0-1, higher = better
    merged.set(r.sourcePath, {
      id: r.id,
      title: r.title,
      sourcePath: r.sourcePath,
      agent: r.agent,
      ftsRank: r.rank,
      similarity: null,
      combinedScore: normalizedFts * ftsWeight,
    });
  }

  for (const r of vecResults) {
    const normalizedVec = r.similarity / maxSimilarity; // 0-1, higher = better
    const existing = merged.get(r.sourcePath);
    if (existing) {
      existing.similarity = r.similarity;
      existing.combinedScore += normalizedVec * vectorWeight;
    } else {
      merged.set(r.sourcePath, {
        id: r.id,
        title: r.title,
        sourcePath: r.sourcePath,
        agent: r.agent,
        ftsRank: null,
        similarity: r.similarity,
        combinedScore: normalizedVec * vectorWeight,
      });
    }
  }

  // Apply knowledge staleness penalties
  const raw = getRawDb();
  for (const r of merged.values()) {
    const meta = raw.prepare(
      "SELECT last_reinforced_at, updated_at FROM memories WHERE source_path = ?"
    ).get(r.sourcePath) as { last_reinforced_at: string | null; updated_at: string } | null;
    if (meta) {
      r.combinedScore *= knowledgeStaleness(meta.last_reinforced_at, meta.updated_at);
    }
  }

  return [...merged.values()]
    .sort((a, b) => b.combinedScore - a.combinedScore)
    .slice(0, limit);
}

// ─── Hybrid search: reference chunks ────────────────────────

export interface ChunkSearchResult {
  chunkId: number;
  sourcePath: string;
  collection: string;
  sectionName: string;
  content: string;
  lineStart: number;
  lineEnd: number;
  tags: string | null;
  ftsScore: number;
  vecScore: number;
  combinedScore: number;
}

/**
 * Hybrid search on reference chunks: FTS5 keyword + sqlite-vec KNN.
 */
export function hybridSearchChunks(
  query: string,
  queryEmbedding: number[],
  opts?: { collection?: string; limit?: number; ftsWeight?: number; vecWeight?: number; minScore?: number },
): ChunkSearchResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 10;
  const ftsWeight = opts?.ftsWeight ?? 0.3;
  const vecWeight = opts?.vecWeight ?? 0.7;
  const minScore = opts?.minScore ?? 0;
  const queryBuf = vectorToBuffer(queryEmbedding);

  // FTS5 results
  const ftsQuery = sanitizeFtsQuery(query);
  let ftsSql = `
    SELECT rc.id, rc.source_path, rc.collection, rc.section_name, rc.content,
           rc.line_start, rc.line_end, rc.tags, rank
    FROM chunks_fts
    JOIN reference_chunks rc ON rc.id = chunks_fts.rowid
    WHERE chunks_fts MATCH ?
  `;
  const ftsParams: any[] = [ftsQuery];
  if (opts?.collection) { ftsSql += " AND rc.collection = ?"; ftsParams.push(opts.collection); }
  ftsSql += ` ORDER BY rank LIMIT ?`;
  ftsParams.push(limit * 2);

  const ftsRows = raw.prepare(ftsSql).all(...ftsParams) as any[];

  // Vector KNN results — get extra results then filter by collection in JS
  const knnLimit = opts?.collection ? limit * 4 : limit * 2;
  const vecRowsRaw = raw.prepare(`
    SELECT vc.chunk_id, vc.distance, rc.source_path, rc.collection, rc.section_name,
           rc.content, rc.line_start, rc.line_end, rc.tags
    FROM vec_chunks vc
    JOIN reference_chunks rc ON rc.id = vc.chunk_id
    WHERE vc.embedding MATCH ? AND k = ?
    ORDER BY vc.distance
  `).all(queryBuf, knnLimit) as any[];

  const vecRows = opts?.collection
    ? vecRowsRaw.filter((r: any) => r.collection === opts.collection).slice(0, limit * 2)
    : vecRowsRaw;

  // Normalize and merge
  const maxFtsRank = Math.min(...ftsRows.map((r: any) => r.rank), -0.001);
  const maxDistance = Math.max(...vecRows.map((r: any) => r.distance), 0.001);

  const merged = new Map<number, ChunkSearchResult>();

  for (const r of ftsRows) {
    const normalizedFts = r.rank / maxFtsRank;
    merged.set(r.id, {
      chunkId: r.id, sourcePath: r.source_path, collection: r.collection,
      sectionName: r.section_name, content: r.content,
      lineStart: r.line_start, lineEnd: r.line_end, tags: r.tags,
      ftsScore: normalizedFts, vecScore: 0, combinedScore: normalizedFts * ftsWeight,
    });
  }

  for (const r of vecRows) {
    const normalizedVec = 1 - (r.distance / maxDistance); // distance → similarity (lower distance = higher score)
    const existing = merged.get(r.chunk_id);
    if (existing) {
      existing.vecScore = normalizedVec;
      existing.combinedScore += normalizedVec * vecWeight;
    } else {
      merged.set(r.chunk_id, {
        chunkId: r.chunk_id, sourcePath: r.source_path, collection: r.collection,
        sectionName: r.section_name, content: r.content,
        lineStart: r.line_start, lineEnd: r.line_end, tags: r.tags,
        ftsScore: 0, vecScore: normalizedVec, combinedScore: normalizedVec * vecWeight,
      });
    }
  }

  return [...merged.values()]
    .filter((r) => r.combinedScore >= minScore)
    .sort((a, b) => b.combinedScore - a.combinedScore)
    .slice(0, limit);
}

// ─── Hybrid search: decisions ───────────────────────────────

export interface DecisionHybridResult {
  id: number;
  agent: string;
  decision: string;
  context: string;
  outcome: string | null;
  confidence: number | null;
  tags: string | null;
  ftsScore: number;
  vecScore: number;
  combinedScore: number;
}

/**
 * Hybrid search on decisions: FTS5 keyword + sqlite-vec KNN.
 */
export function hybridSearchDecisions(
  query: string,
  queryEmbedding: number[],
  opts?: { agent?: string; project?: string; limit?: number; ftsWeight?: number; vecWeight?: number },
): DecisionHybridResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 10;
  const ftsWeight = opts?.ftsWeight ?? 0.3;
  const vecWeight = opts?.vecWeight ?? 0.7;
  const queryBuf = vectorToBuffer(queryEmbedding);

  // FTS5
  const ftsQuery = sanitizeFtsQuery(query);
  const ftsRows = raw.prepare(`
    SELECT d.id, d.agent, d.decision, d.context, d.outcome, d.confidence, d.tags, rank
    FROM decisions_fts
    JOIN decisions d ON d.id = decisions_fts.rowid
    WHERE decisions_fts MATCH ?
    ORDER BY rank LIMIT ?
  `).all(ftsQuery, limit * 2) as any[];

  // Vector KNN
  const vecRows = raw.prepare(`
    SELECT vd.decision_id, vd.distance, d.agent, d.decision, d.context, d.outcome, d.confidence, d.tags
    FROM vec_decisions vd
    JOIN decisions d ON d.id = vd.decision_id
    WHERE vd.embedding MATCH ? AND k = ?
    ORDER BY vd.distance
  `).all(queryBuf, limit * 2) as any[];

  const maxFtsRank = Math.min(...ftsRows.map((r: any) => r.rank), -0.001);
  const maxDistance = Math.max(...vecRows.map((r: any) => r.distance), 0.001);

  const merged = new Map<number, DecisionHybridResult>();

  for (const r of ftsRows) {
    if (opts?.agent && r.agent !== opts.agent) continue;
    const normalizedFts = r.rank / maxFtsRank;
    merged.set(r.id, {
      id: r.id, agent: r.agent, decision: r.decision, context: r.context,
      outcome: r.outcome, confidence: r.confidence, tags: r.tags,
      ftsScore: normalizedFts, vecScore: 0, combinedScore: normalizedFts * ftsWeight,
    });
  }

  for (const r of vecRows) {
    if (opts?.agent && r.agent !== opts.agent) continue;
    const normalizedVec = 1 - (r.distance / maxDistance);
    const existing = merged.get(r.decision_id);
    if (existing) {
      existing.vecScore = normalizedVec;
      existing.combinedScore += normalizedVec * vecWeight;
    } else {
      merged.set(r.decision_id, {
        id: r.decision_id, agent: r.agent, decision: r.decision, context: r.context,
        outcome: r.outcome, confidence: r.confidence, tags: r.tags,
        ftsScore: 0, vecScore: normalizedVec, combinedScore: normalizedVec * vecWeight,
      });
    }
  }

  // Apply extended confidence decay (failed outcomes decay faster)
  const rawDb = getRawDb();
  for (const r of merged.values()) {
    const meta = rawDb.prepare(
      "SELECT created_at, outcome FROM decisions WHERE id = ?"
    ).get(r.id) as { created_at: string; outcome: string | null } | null;
    if (meta) {
      const decay = decayedConfidence(r.confidence, meta.created_at, meta.outcome);
      // Scale score by decay ratio
      const decayRatio = r.confidence ? decay / r.confidence : 1;
      r.combinedScore *= decayRatio;
    }
  }

  return [...merged.values()]
    .sort((a, b) => b.combinedScore - a.combinedScore)
    .slice(0, limit);
}

