// ─── Unified cross-store search ─────────────────────────────

export interface SearchAllResult {
  references: ChunkSearchResult[];
  memories: HybridSearchResult[];
  decisions: DecisionHybridResult[];
  projects: ProjectChunkResult[];
}

/**
 * Search across all knowledge stores in one call.
 * If `agent` is provided, results are reranked with the agent's boost profile.
 */
export function searchAll(
  query: string,
  queryEmbedding: number[],
  opts?: {
    stores?: ("refs" | "memories" | "decisions" | "projects")[];
    limit?: number;
    collection?: string;
    agent?: string;
    project?: string;
  },
): SearchAllResult {
  const stores = opts?.stores ?? ["refs", "memories", "decisions", "projects"];
  const limit = opts?.limit ?? 5;

  const result: SearchAllResult = { references: [], memories: [], decisions: [], projects: [] };

  if (stores.includes("refs")) {
    result.references = hybridSearchChunks(query, queryEmbedding, { collection: opts?.collection, limit });
  }
  if (stores.includes("memories")) {
    result.memories = hybridSearchMemories(query, queryEmbedding, { agent: opts?.agent, limit });
  }
  if (stores.includes("decisions")) {
    result.decisions = hybridSearchDecisions(query, queryEmbedding, { agent: opts?.agent, limit });
  }
  if (stores.includes("projects")) {
    result.projects = hybridSearchProjects(query, queryEmbedding, { project: opts?.project, limit });
  }

  // Apply agent-context reranking
  rerankResults(result, opts?.agent);

  return result;
}

// ─── Hybrid search: raw chunks ──────────────────────────────

export interface RawChunkResult {
  chunkId: number;
  rawId: number;
  ts: number;
  date: string;
  agents: string;
  skill: string | null;
  sectionName: string;
  content: string;
  summary: string | null;
  ftsScore: number;
  vecScore: number;
  combinedScore: number;
}

/**
 * Hybrid search on raw chunks: FTS5 keyword + sqlite-vec KNN.
 * Joins raw_chunks back to raw_files for metadata (ts, date, agents, skill, summary).
 *
 * @param opts.skill - Filter to specific skill (e.g. "/create-track")
 * @param opts.dateFrom - Filter by date >= value (YYYY-MM-DD)
 * @param opts.dateTo - Filter by date <= value (YYYY-MM-DD)
 */
export function hybridSearchRaw(
  query: string,
  queryEmbedding: number[],
  opts?: {
    skill?: string;
    dateFrom?: string;
    dateTo?: string;
    limit?: number;
    ftsWeight?: number;
    vecWeight?: number;
  },
): RawChunkResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 10;
  const ftsWeight = opts?.ftsWeight ?? 0.3;
  const vecWeight = opts?.vecWeight ?? 0.7;
  const queryBuf = vectorToBuffer(queryEmbedding);

  // FTS5 query
  const ftsQuery = sanitizeFtsQuery(query);
  let ftsSql = `
    SELECT rc.id, rc.raw_id, rc.section_name, rc.content,
           rf.ts, rf.date, rf.agents, rf.skill, rf.summary, rank
    FROM raw_fts
    JOIN raw_chunks rc ON rc.id = raw_fts.rowid
    JOIN raw_files rf ON rf.id = rc.raw_id
    WHERE raw_fts MATCH ?
  `;
  const ftsParams: any[] = [ftsQuery];
  if (opts?.skill) { ftsSql += " AND rf.skill = ?"; ftsParams.push(opts.skill); }
  if (opts?.dateFrom) { ftsSql += " AND rf.date >= ?"; ftsParams.push(opts.dateFrom); }
  if (opts?.dateTo) { ftsSql += " AND rf.date <= ?"; ftsParams.push(opts.dateTo); }
  ftsSql += " ORDER BY rank LIMIT ?";
  ftsParams.push(limit * 2);
  const ftsRows = raw.prepare(ftsSql).all(...ftsParams) as any[];

  // Vector KNN
  const knnLimit = opts?.skill ? limit * 4 : limit * 2;
  const vecRowsRaw = raw.prepare(`
    SELECT vr.chunk_id, vr.distance, rc.raw_id, rc.section_name, rc.content,
           rf.ts, rf.date, rf.agents, rf.skill, rf.summary
    FROM vec_raw vr
    JOIN raw_chunks rc ON rc.id = vr.chunk_id
    JOIN raw_files rf ON rf.id = rc.raw_id
    WHERE vr.embedding MATCH ? AND k = ?
    ORDER BY vr.distance
  `).all(queryBuf, knnLimit) as any[];

  const vecRows = opts?.skill
    ? vecRowsRaw.filter((r: any) => r.skill === opts.skill).slice(0, limit * 2)
    : vecRowsRaw;

  // Apply date filter to vec results
  const filteredVecRows = vecRows.filter((r: any) => {
    if (opts?.dateFrom && r.date < opts.dateFrom) return false;
    if (opts?.dateTo && r.date > opts.dateTo) return false;
    return true;
  });

  // Normalize and merge
  const maxFtsRank = Math.min(...ftsRows.map((r: any) => r.rank), -0.001);
  const maxDistance = Math.max(...filteredVecRows.map((r: any) => r.distance), 0.001);

  const merged = new Map<number, RawChunkResult>();

  for (const r of ftsRows) {
    const normalizedFts = r.rank / maxFtsRank;
    merged.set(r.id, {
      chunkId: r.id, rawId: r.raw_id, ts: r.ts, date: r.date,
      agents: r.agents, skill: r.skill, sectionName: r.section_name,
      content: r.content, summary: r.summary,
      ftsScore: normalizedFts, vecScore: 0, combinedScore: normalizedFts * ftsWeight,
    });
  }

  for (const r of filteredVecRows) {
    const normalizedVec = 1 - (r.distance / maxDistance);
    const existing = merged.get(r.chunk_id);
    if (existing) {
      existing.vecScore = normalizedVec;
      existing.combinedScore += normalizedVec * vecWeight;
    } else {
      merged.set(r.chunk_id, {
        chunkId: r.chunk_id, rawId: r.raw_id, ts: r.ts, date: r.date,
        agents: r.agents, skill: r.skill, sectionName: r.section_name,
        content: r.content, summary: r.summary,
        ftsScore: 0, vecScore: normalizedVec, combinedScore: normalizedVec * vecWeight,
      });
    }
  }

  // Apply staleness degradation using raw_files.created_at
  for (const r of merged.values()) {
    const meta = raw.prepare(
      "SELECT created_at FROM raw_files WHERE id = ?"
    ).get(r.rawId) as { created_at: string } | null;
    if (meta) {
      r.combinedScore *= knowledgeStaleness(null, meta.created_at);
    }
  }

  return [...merged.values()]
    .sort((a, b) => b.combinedScore - a.combinedScore)
    .slice(0, limit);
}

// ─── Recall search (all stores including raw) ────────────────

export interface RecallResult extends SearchAllResult {
  raw: RawChunkResult[];
}

/**
 * Recall search — searches ALL stores including raw.
 * Used for conversational memory: "what did we discuss about X?"
 */
export function searchRecall(
  query: string,
  queryEmbedding: number[],
  opts?: {
    stores?: ("refs" | "memories" | "decisions" | "projects" | "raw")[];
    limit?: number;
    collection?: string;
    agent?: string;
    skill?: string;
  },
): RecallResult {
  const stores = opts?.stores ?? ["refs", "memories", "decisions", "projects", "raw"];
  const limit = opts?.limit ?? 5;

  // Run standard searchAll for the non-raw stores
  const standardStores = stores.filter((s): s is "refs" | "memories" | "decisions" | "projects" =>
    s !== "raw"
  );
  const base = searchAll(query, queryEmbedding, {
    stores: standardStores.length > 0 ? standardStores : undefined,
    limit,
    collection: opts?.collection,
    agent: opts?.agent,
  });

  // Raw store
  let rawResults: RawChunkResult[] = [];
  if (stores.includes("raw")) {
    rawResults = hybridSearchRaw(query, queryEmbedding, { skill: opts?.skill, limit });
  }

  return { ...base, raw: rawResults };
}

// ─── Tool-based raw search ──────────────────────────────────

export interface RawToolSearchResult {
  rawId: number;
  sessionId: string | null;
  date: string;
  skill: string | null;
  summary: string | null;
  toolName: string;
  toolUseCount: number;
}

/**
 * Find raw sessions that used a specific tool.
 * Groups by raw_files to show one row per session with tool use count.
 *
 * @param toolName - exact tool name (e.g. "Read", "Bash", "Write")
 * @param opts.limit - max results (default 20)
 * @param opts.dateFrom - filter by date >= (YYYY-MM-DD)
 * @param opts.dateTo - filter by date <= (YYYY-MM-DD)
 */
export function searchRawByTool(
  toolName: string,
  opts?: { limit?: number; dateFrom?: string; dateTo?: string },
): RawToolSearchResult[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 20;

  let sqlStr = `
    SELECT rf.id as raw_id, rf.session_id, rf.date, rf.skill, rf.summary,
           rtc.tool_name, COUNT(*) as tool_use_count
    FROM raw_tool_calls rtc
    JOIN raw_files rf ON rf.id = rtc.raw_id
    WHERE rtc.tool_name = ?
  `;
  const params: any[] = [toolName];

  if (opts?.dateFrom) {
    sqlStr += " AND rf.date >= ?";
    params.push(opts.dateFrom);
  }
  if (opts?.dateTo) {
    sqlStr += " AND rf.date <= ?";
    params.push(opts.dateTo);
  }

  sqlStr += " GROUP BY rf.id ORDER BY rf.date DESC LIMIT ?";
  params.push(limit);

  const rows = raw.prepare(sqlStr).all(...params) as any[];
  return rows.map((r) => ({
    rawId: r.raw_id,
    sessionId: r.session_id,
    date: r.date,
    skill: r.skill,
    summary: r.summary,
    toolName: r.tool_name,
    toolUseCount: r.tool_use_count,
  }));
}

// ─── Entity tracking ────────────────────────────────────────

export interface EntityResult {
  id: number;
  name: string;
  type: string;
  summary: string | null;
}

export interface EntityRelationResult {
  id: number;
  sourceName: string;
  targetName: string;
  relation: string;
  weight: number;
  evidence: string | null;
}

/** Upsert an entity. Returns the entity ID. */
export function upsertEntity(name: string, type: string, summary?: string): number {
  const db = getDb();
  const ts = new Date().toISOString();
  const normalized = name.toLowerCase();

  const existing = db.select({ id: entities.id }).from(entities).where(eq(entities.name, normalized)).get();

  if (existing) {
    db.update(entities)
      .set({ type, summary: summary ?? undefined, updatedAt: ts })
      .where(eq(entities.id, existing.id))
      .run();
    return existing.id;
  }

  const [row] = db.insert(entities).values({
    name: normalized, type, summary: summary ?? null, createdAt: ts, updatedAt: ts,
  }).returning({ id: entities.id }).all();
  return row.id;
}

/** Add a relation between two entities. Deduplicates by source+target+relation. */
export function addEntityRelation(
  sourceId: number,
  targetId: number,
  relation: string,
  evidence?: string,
  weight = 1.0,
): void {
  const db = getDb();
  const ts = new Date().toISOString();

  const existing = db.select({ id: entityRelations.id, weight: entityRelations.weight })
    .from(entityRelations)
    .where(and(
      eq(entityRelations.sourceId, sourceId),
      eq(entityRelations.targetId, targetId),
      eq(entityRelations.relation, relation),
    ))
    .get();

  if (existing) {
    db.update(entityRelations)
      .set({ weight: (existing.weight ?? 1) + 0.5, evidence: evidence ?? undefined })
      .where(eq(entityRelations.id, existing.id))
      .run();
  } else {
    db.insert(entityRelations).values({
      sourceId, targetId, relation, weight, evidence: evidence ?? null, createdAt: ts,
    }).run();
  }
}

/** Look up an entity by name (case-insensitive). */
export function getEntity(name: string): EntityResult | null {
  const db = getDb();
  const row = db.select({
    id: entities.id, name: entities.name, type: entities.type, summary: entities.summary,
  }).from(entities).where(eq(entities.name, name.toLowerCase())).get();
  return row ?? null;
}

/** Search entities by name prefix or substring. */
export function searchEntities(query: string, opts?: { type?: string; limit?: number }): EntityResult[] {
  const db = getDb();
  const limit = opts?.limit ?? 20;
  const pattern = `%${query.toLowerCase()}%`;

  const q = db.select({
    id: entities.id, name: entities.name, type: entities.type, summary: entities.summary,
  }).from(entities).where(
    opts?.type
      ? and(sql`${entities.name} LIKE ${pattern}`, eq(entities.type, opts.type))
      : sql`${entities.name} LIKE ${pattern}`
  ).limit(limit);

  return q.all();
}

/** Get all relations for an entity (both as source and target). Raw SQL for the JOIN. */
export function getEntityRelations(entityId: number): EntityRelationResult[] {
  const raw = getRawDb();
  const rows = raw.prepare(`
    SELECT er.id, es.name as source_name, et.name as target_name,
           er.relation, er.weight, er.evidence
    FROM entity_relations er
    JOIN entities es ON es.id = er.source_id
    JOIN entities et ON et.id = er.target_id
    WHERE er.source_id = ? OR er.target_id = ?
    ORDER BY er.weight DESC
  `).all(entityId, entityId) as any[];

  return rows.map(r => ({
    id: r.id, sourceName: r.source_name, targetName: r.target_name,
    relation: r.relation, weight: r.weight, evidence: r.evidence,
  }));
}

/** Get entity stats. */
export function getEntityStats(): { entities: number; relations: number } {
  const db = getDb();
  const [e] = db.select({ n: sql<number>`COUNT(*)` }).from(entities).all();
  const [r] = db.select({ n: sql<number>`COUNT(*)` }).from(entityRelations).all();
  return { entities: e.n, relations: r.n };
}

