export interface BrainStats {
  memories: number;
  references: number;
  decisions: number;
  lastSync: string | null;
  agents: string[];
}

/** Get counts and metadata about brain.db contents. */
export function getStats(): BrainStats {
  const db = getDb();

  const [memCount] = db.select({ n: sql<number>`COUNT(*)` }).from(memories).all();
  const [refCount] = db.select({ n: sql<number>`COUNT(*)` }).from(references).all();
  const [decCount] = db.select({ n: sql<number>`COUNT(*)` }).from(decisions).all();
  const [lastSync] = db.select({ ts: sql<string | null>`MAX(synced_at)` }).from(syncMeta).all();
  const agents = db.selectDistinct({ agent: memories.agent }).from(memories).orderBy(memories.agent).all();

  return {
    memories: memCount.n,
    references: refCount.n,
    decisions: decCount.n,
    lastSync: lastSync.ts,
    agents: agents.map((a) => a.agent),
  };
}

/**
 * brain/queries.ts — Query functions for brain.db
 *
 * All search functions use FTS5 with BM25 ranking.
 * Decision functions handle logging, recall, and outcome updates.
 */

import { eq, and, desc, sql } from "drizzle-orm";
import { getDb, getRawDb } from "../sqlite.js";
import { memories, references, decisions, entities, entityRelations, syncMeta } from "./schema.js";
import { vectorToBuffer, embedText, EMBEDDING_CONFIG } from "../embeddings.js";
import { rerankResults } from "./reranker.js";
import { knowledgeStaleness, decayedConfidence } from "./degradation.js";

/**
 * Sanitize a user query for FTS5.
 * - Wraps each token in quotes to avoid operator parsing (e.g., lo-fi → "lo-fi")
 * - Joins with spaces (implicit AND in FTS5)
 */
function sanitizeFtsQuery(query: string): string {
  return query
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((token) => `"${token.replace(/"/g, "")}"`)
    .join(" ");
}

